function solve(points: number[][]): number {
    const n = points.length;
    const slopeHash: Record<string, number> = {};

    // Iterate over all pairs of points to find potential parallel lines
    for (let i = 0; i < n; i++) {
        const [x1, y1] = points[i];
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const [x2, y2] = points[j];
            const dx = x2 - x1;
            const dy = y2 - y1;

            // Calculate the greatest common divisor
            const gcd = (a: number, b: number): number => {
