            // Normalize the slope to avoid duplicates like (2, 4) and (1, 2)
            const slopeKey = `${dxReduced},${dyReduced}`;
            slopeHash[slopeKey] = (slopeHash[slopeKey] || 0) + 1;
        }
    }

    let count = 0;

    // Now, for each pair of points, check if there are at least two other points with the same slope
    for (const [slope, cnt] of Object.entries(slopeHash)) {
